import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import shuffle from "lodash/shuffle";
import { connect } from "react-redux";
import buildActions from "../../../store/actions";
import { InjectLocale } from "../../../../../decorators/locale";
import { sendScore } from "../../../../../utils/score";
import { FeedbackSoundManager } from "../../../../../utils/sound";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import { isSafari, isIE } from "../../../../../../common/constants/user-agent";
import { Key } from "../../../../../../common/constants/keyboard";
import { trapTabKey } from "../../../../../utils/accessibility";
import Prompt from "../Prompt/Prompt";
import Feedback from "../Feedback/Feedback";
import Controls from "../Controls/Controls";
import Body from "../Body/Body";

@connect(
  state => ({
    activityId: state.id,
    activityType: state.type,
    activityName: state.name,
    showAnswers: state.showAnswers,
    allowRetry: state.allowRetry,
    playFeedbackSounds: state.playFeedbackSounds,
    score: state.score,
    positiveResponse: state.positiveResponse,
    negativeResponse: state.negativeResponse,
    finalResponse: "Completed!",
    studentInstruction: state.studentInstruction,
    spots: state.spots,
    viewBox: {
      ...state.viewBox,
      x: state.viewBox.left,
      y: state.viewBox.top
    },
    image: state.image
  }),
  buildActions
)
@InjectLocale("Activity")
class Activity extends PureComponent {
  static propTypes = {
    activityAlign: PropTypes.object,
    activityId: PropTypes.number.isRequired,
    activityType: PropTypes.string.isRequired,
    activityName: PropTypes.string.isRequired,
    showAnswers: PropTypes.bool.isRequired,
    allowRetry: PropTypes.bool.isRequired,
    playFeedbackSounds: PropTypes.bool.isRequired,
    score: PropTypes.number.isRequired,
    studentInstruction: PropTypes.string.isRequired,
    spots: PropTypes.array.isRequired,
    viewBox: PropTypes.object.isRequired,
    image: PropTypes.object.isRequired,
    finalResponse: PropTypes.string.isRequired,
    positiveResponse: PropTypes.string.isRequired,
    negativeResponse: PropTypes.string.isRequired
  };

  shuffledSpots = shuffle(this.props.spots);

  state = Object.assign({}, this.initialState, { svgWidth: 0, feedback: "" });

  feedbackTimer = null;

  playerStyle = {
    ...this.props.activityAlign
  };

  componentDidMount() {
    const { activityId, activityType } = this.props;
    const activityData = JSON.parse(sessionStorage.getItem(`${activityType}-${activityId}`));

    if (
      activityData &&
      activityData.hasOwnProperty("pointsEarned") &&
      activityData.hasOwnProperty("isRestart")
    ) {
      if (activityData.isRestart === false) {
        this.setState({
          displayedScore: activityData.pointsEarned,
          complete: true
        });
      }
    }

    if (isIE || isSafari) {
      window.addEventListener("resize", this.onResize);
    }

    let event;

    if (typeof Event === "function") {
      event = new Event("resize");
    } else {
      event = document.createEvent("Event");
      event.initEvent("resize", true, true);
    }

    window.dispatchEvent(event);
  }

  componentWillUnmount() {
    if (isIE || isSafari) {
      window.removeEventListener("resize", this.onResize);
    }
  }

  onResize = () => {
    this.setState({
      svgWidth: this.refs.body.clientSize.width
    });
  };

  onSvgMouseDown = () => {
    if (!this.state.complete) {
      this.handleIncorrectClick();
      this.clearFeedback();
    }
  };

  onSpotMouseDown = data => {
    if (!this.state.complete) {
      if (data.id === this.shuffledSpots[this.state.currentSpotIndex].id) {
        this.handleCorrectClick();
      } else {
        this.handleIncorrectClick();
      }

      this.clearFeedback();
    }
  };

  clearFeedback() {
    if (this.feedbackTimer) {
      clearTimeout(this.feedbackTimer);
    }

    this.feedbackTimer = setTimeout(() => {
      this.setState({
        feedback: null,
        ariaText: ""
      });
    }, 2000);
  }

  updateRolloverText = rolloverText => {
    this.setState({
      rolloverText
    });
  };

  handleCorrectClick() {
    const { playFeedbackSounds, activityId, activityType, score } = this.props;
    const currentScore = this.state.mistake ? this.state.currentScore : this.state.currentScore + 1;
    const displayedScore = parseFloat(
      ((score * currentScore) / this.shuffledSpots.length).toFixed(1)
    );
    let currentSpotIndex = this.state.currentSpotIndex + 1;
    let complete = this.state.complete;

    if (currentSpotIndex === this.shuffledSpots.length) {
      currentSpotIndex--;
      complete = true;
      sendScore({
        id: activityId,
        type: activityType,
        pointsEarned: displayedScore,
        maxValue: score,
        isRestart: false
      });
    }

    if (playFeedbackSounds) {
      FeedbackSoundManager.playCorrect();
    }

    this.setState({
      currentSpotIndex,
      feedback: complete ? "finalResponse" : "positiveResponse",
      mistake: false,
      currentScore,
      displayedScore,
      complete,
      ariaText: complete ? this.locale.finish : this.locale.correct
    });
  }

  handleIncorrectClick() {
    const { playFeedbackSounds } = this.props;

    if (playFeedbackSounds) {
      FeedbackSoundManager.playWrong();
    }

    this.setState({
      feedback: "negativeResponse",
      mistake: true,
      ariaText: this.locale.incorrect
    });
  }

  completeActivity = () => {
    const { complete, displayedScore } = this.state;

    if (!complete) {
      const { activityId, activityType, score } = this.props;

      sendScore({
        id: activityId,
        type: activityType,
        pointsEarned: displayedScore,
        maxValue: score,
        isRestart: false
      });

      this.setState({
        complete: true,
        ariaText: this.locale.complete_activity
      });
    }
  };

  skip = () => {
    if (!this.state.complete) {
      let currentSpotIndex = this.state.currentSpotIndex + 1;
      let complete = this.state.complete;

      if (currentSpotIndex === this.shuffledSpots.length) {
        currentSpotIndex--;
        complete = true;
      }

      this.setState({
        currentSpotIndex,
        complete,
        mistake: false,
        ariaText: this.locale.skip
      });
    }
  };

  restart = () => {
    if (this.props.allowRetry) {
      sendScore({
        id: this.props.activityId,
        type: this.props.activityType,
        pointsEarned: 0,
        maxValue: this.props.score,
        isRestart: true
      });

      this.shuffledSpots = shuffle(this.props.spots);
      this.setState({
        ...this.initialState,
        ariaText: this.locale.restart
      });
    }
  };

  onActivityKeyDown = e => {
    if (e.altKey) {
      switch (e.keyCode) {
        case Key.R:
          e.preventDefault();
          this.restart();
          break;
        case Key.S:
          e.preventDefault();
          this.completeActivity();
          break;
        case Key.N:
          e.preventDefault();
          this.skip();
          break;
        case Key.Q:
          e.preventDefault();
          this.setState({
            focusLoop: false,
            ariaText: this.locale.noloop
          });
          break;
        default:
      }
    }
  };

  onActivityFocus = e => {
    if (!this.refs.body.contains(e.target) && !this.state.focusLoop) {
      this.setState({
        focusLoop: true,
        ariaText: ""
      });
    }
  };

  onActivityTouchEnd = () => {
    this.refs.prompt.onPromptLeave();
  };

  onSvgWrapperKeyDown = e => {
    if (e.keyCode === Key.TAB && this.state.focusLoop) {
      trapTabKey(e);
    }
  };

  get initialState() {
    return {
      currentSpotIndex: 0,
      currentScore: 0,
      displayedScore: 0,
      mistake: false,
      complete: false,
      ariaText: "",
      focusLoop: true
    };
  }

  render() {
    return (
      <section
        tabIndex="0"
        className={styles.container}
        onKeyDown={this.onActivityKeyDown}
        onFocus={this.onActivityFocus}
        onTouchEnd={this.onActivityTouchEnd}
      >
        <AdaHelper ariaText={this.state.ariaText} />
        <ActivityHeader
          activityName={this.props.activityName}
          studentInstruction={this.props.studentInstruction}
        />
        <div style={this.playerStyle} className={styles.player}>
          <Controls
            allowRetry={this.props.allowRetry}
            displayedScore={this.state.displayedScore}
            score={this.props.score}
            complete={this.state.complete}
            skip={this.skip}
            restart={this.restart}
            completeActivity={this.completeActivity}
          />
          <Prompt
            ref="prompt"
            text={
              this.state.complete
                ? this.state.rolloverText || this.props.finalResponse
                : this.shuffledSpots[this.state.currentSpotIndex].title
            }
          />
          <Body
            ref="body"
            activityId={this.props.activityId}
            showAnswers={this.props.showAnswers}
            complete={this.state.complete}
            image={this.props.image}
            viewBox={this.props.viewBox}
            svgWidth={this.state.svgWidth}
            localeHotspotsBlock={this.locale.hotspotsBlock}
            spots={this.props.spots}
            currentSpotIndex={this.state.currentSpotIndex}
            onSvgWrapperKeyDown={this.onSvgWrapperKeyDown}
            onSvgMouseDown={this.onSvgMouseDown}
            updateRolloverText={this.updateRolloverText}
            onSpotMouseDown={this.onSpotMouseDown}
          />
          <Feedback
            finalResponse={this.props.finalResponse}
            positiveResponse={this.props.positiveResponse}
            negativeResponse={this.props.negativeResponse}
            feedback={this.state.feedback}
          />
        </div>
      </section>
    );
  }
}

export default Activity;
