import styles from "./Body.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import SvgElement from "../../../../common/components/SvgElement/SvgElement";
import { Classes } from "../../../../../../common/constants/classes";
import SvgImage from "../../../../common/components/SvgImage/SvgImage";
import BaseSpot from "../../../../common/components/BaseSpot/BaseSpot";
import { isIE, isSafari } from "../../../../../../common/constants/user-agent";

export default class Body extends PureComponent {
  static propTypes = {
    activityId: PropTypes.number.isRequired,
    showAnswers: PropTypes.bool.isRequired,
    complete: PropTypes.bool.isRequired,
    image: PropTypes.object.isRequired,
    viewBox: PropTypes.object.isRequired,
    svgWidth: PropTypes.number.isRequired,
    localeHotspotsBlock: PropTypes.string.isRequired,
    spots: PropTypes.array.isRequired,
    currentSpotIndex: PropTypes.number.isRequired,
    onSvgWrapperKeyDown: PropTypes.func.isRequired,
    onSvgMouseDown: PropTypes.func.isRequired,
    updateRolloverText: PropTypes.func.isRequired,
    onSpotMouseDown: PropTypes.func.isRequired
  };

  get svgSize() {
    const { svgWidth, image } = this.props;
    const svgSize = {
      maxWidth: image.width,
      maxHeight: image.height
    };

    if ((isIE || isSafari) && svgWidth) {
      svgSize.width = svgWidth;
      svgSize.height = (svgWidth / image.width) * image.height;
    }

    return svgSize;
  }

  get clientSize() {
    const { body } = this.refs;

    return {
      width: body.clientWidth,
      height: body.clientHeight
    };
  }

  contains(element) {
    return this.refs.body.contains(element);
  }

  render() {
    const {
      activityId,
      showAnswers,
      complete,
      image,
      viewBox,
      spots,
      currentSpotIndex,
      localeHotspotsBlock,
      onSvgWrapperKeyDown,
      onSvgMouseDown,
      updateRolloverText,
      onSpotMouseDown
    } = this.props;

    return (
      <div
        ref="body"
        tabIndex="0"
        role="application"
        aria-label={`${localeHotspotsBlock} ${spots[currentSpotIndex].title}`}
        className={styles.container}
        onKeyDown={onSvgWrapperKeyDown}
      >
        <SvgElement
          className={!complete ? Classes.POINTER : ""}
          viewBox={viewBox}
          {...this.svgSize}
          onMouseDown={onSvgMouseDown}
        >
          <SvgImage viewBox={viewBox} url={image.url} />
          {spots.map((item, key) => (
            <BaseSpot
              key={key}
              activityId={activityId}
              mode="quiz"
              complete={complete}
              visible={showAnswers && complete}
              updateHandler={updateRolloverText}
              hitHandler={onSpotMouseDown}
              {...item}
            />
          ))}
        </SvgElement>
      </div>
    );
  }
}
