import styles from "./Prompt.module.scss";
import PropTypes from "prop-types";
import React, { PureComponent } from "react";
import classNames from "classnames";
import Truncate from "react-truncate";
import { getClientPosition } from "../../../../../../common/utils/event";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import Popup from "../../../../common/components/Popup/Popup";

export default class Prompt extends PureComponent {
  static propTypes = {
    text: PropTypes.string
  };

  static defaultProps = {
    text: ""
  };

  promptContainer = null;
  popupRef = null;

  state = {
    isTruncated: false
  };

  onPromptEnter = e => {
    e.stopPropagation();
    const { text } = this.props;

    if (this.state.isTruncated) {
      const { x: left, y: top } = getClientPosition(e);

      this.popupRef.update(
        {
          show: true,
          content: text,
          pos: { left, top }
        },
        this.promptContainer
      );
    }
  };

  onPromptLeave = () => {
    const { show } = this.popupRef.state;

    if (show) {
      this.popupRef.update({
        show: false
      });
    }
  };

  onTruncate = truncate => {
    if (truncate !== this.state.isTruncated) {
      this.setState({
        isTruncated: truncate
      });
    }
  };

  render() {
    const { text } = this.props;

    return (
      <div
        className={classNames(
          styles.container,
          this.state.isTruncated && styles["container-truncated"]
        )}
      >
        <h2
          ref={element => (this.promptContainer = element)}
          className={styles.text}
          onMouseEnter={this.onPromptEnter}
          onMouseLeave={this.onPromptLeave}
          onMouseMove={this.onPromptEnter}
          onTouchEnd={this.onPromptEnter}
        >
          <Truncate lines={2} onTruncate={this.onTruncate}>
            {text}
          </Truncate>
        </h2>
        <AdaHelper ariaText={text} />
        <Popup ref={element => (this.popupRef = element)} />
      </div>
    );
  }
}
