import styles from "./Controls.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { isMobile } from "../../../../../../common/constants/user-agent";
import ShortcutsButton from "../../../../common/components/ShortcutsButton/ShortcutsButton";
import Score from "../../../../common/components/Score/Score";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";

export default class Controls extends PureComponent {
  static propTypes = {
    allowRetry: PropTypes.bool.isRequired,
    displayedScore: PropTypes.number.isRequired,
    score: PropTypes.number.isRequired,
    complete: PropTypes.bool.isRequired,
    skip: PropTypes.func.isRequired,
    completeActivity: PropTypes.func.isRequired,
    restart: PropTypes.func.isRequired
  };

  render() {
    return (
      <div className={styles.container}>
        <div className={classNames(styles.item, styles.navigation)}>
          {!isMobile && <ShortcutsButton excludeItems={{ restart: !this.props.allowRetry }} />}
        </div>
        <div className={classNames(styles.item, styles.score)}>
          <Score displayedScore={this.props.displayedScore} totalScore={this.props.score} />
        </div>
        <div className={classNames(styles.item, styles.buttons)}>
          <Button
            id={Buttons.SKIP}
            disabled={this.props.complete}
            className={buttonStyles.skip}
            onClick={this.props.skip}
            hint={true}
          />
          <Button
            id={Buttons.COMPLETE_ACTIVITY}
            disabled={this.props.complete}
            className={buttonStyles["complete-activity"]}
            onClick={this.props.completeActivity}
            hint={true}
          />
          {this.props.allowRetry && (
            <Button
              id={Buttons.RESTART}
              className={buttonStyles.restart}
              onClick={this.props.restart}
              hint={true}
            />
          )}
        </div>
      </div>
    );
  }
}
