import styles from "./Feedback.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import finalResponse from "../../../../../assets/images/finalResponse.svg";
import negativeResponse from "../../../../../assets/images/negativeResponse.svg";
import positiveResponse from "../../../../../assets/images/positiveResponse.svg";

export default class Feedback extends PureComponent {
  static responseImages = {
    finalResponse,
    negativeResponse,
    positiveResponse
  };

  static propTypes = {
    finalResponse: PropTypes.string.isRequired,
    positiveResponse: PropTypes.string.isRequired,
    negativeResponse: PropTypes.string.isRequired,
    feedback: PropTypes.string
  };

  render() {
    const { feedback } = this.props;

    return (
      <div className={styles.container}>
        {feedback && (
          <div className={styles.inner}>
            <img src={Feedback.responseImages[feedback]} alt="Feedback icon" />
            {this.props[feedback]}
          </div>
        )}
      </div>
    );
  }
}
